const lead = Array.isArray($input.first().json) ? $input.first().json[0] : $input.first().json;
const step = $('Workflow Input').first().json.sequence_step;

const subjectMap = {
  1: 'Your site is being indexed — here\'s what to expect',
  2: 'Quick SEO tip for ' + lead.business_name,
  3: 'One week in — have you had any calls yet?'
};

const bodyMap = {
  1: `<p>Hi,</p>
<p>Your <strong>${lead.business_name}</strong> website is live and Google is already crawling it. You should appear in local search results within 24–72 hours.</p>
<h2>How to check your ranking</h2>
<ol>
<li>Open an incognito window in Chrome</li>
<li>Search for <strong>[your service] ${lead.suburb}</strong></li>
<li>Your site should appear within a week</li>
</ol>
<p>Want to speed things up? Make sure your Google Business Profile links to your new website URL.</p>
<p>— Preview Factory</p>`,
  2: `<p>Hi,</p>
<p>Quick tip: update your Google Business Profile to link directly to your new <strong>${lead.business_name}</strong> website. This sends a strong signal to Google that your site is your official web presence.</p>
<p>Here\'s how:</p>
<ol>
<li>Open <a href="https://business.google.com">business.google.com</a></li>
<li>Click "Edit profile"</li>
<li>Under "Website", paste your site URL</li>
<li>Click Save</li>
</ol>
<p>This one change typically adds 10–20% more impressions within 30 days.</p>
<p>— Preview Factory</p>`,
  3: `<p>Hi,</p>
<p>It\'s been one week since your <strong>${lead.business_name}</strong> website went live. We\'d love to know — have you had any enquiries or calls from people who found you online?</p>
<p>Just reply to this email and let us know. Your feedback helps us improve the service.</p>
<p>And if you\'d like to make any changes to your site — services, photos, contact details — just SMS us at ${$vars.TWILIO_FROM_NUMBER || '[your Twilio number]'} with the update.</p>
<p>— Preview Factory</p>`
};

const textMap = {
  1: 'Your ' + lead.business_name + ' site is live and indexing. Check Google within 72 hours.',
  2: 'Tip: link your Google Business Profile to your new website to improve rankings.',
  3: 'One week in — reply and let us know if you\'ve had any calls from the site.'
};

return [{
  json: {
    lead_id: lead.lead_id,
    business_name: lead.business_name,
    email: lead.email,
    niche: lead.niche,
    suburb: lead.suburb,
    sequence_step: step,
    subject: subjectMap[step] || 'Update from Preview Factory',
    html_body: bodyMap[step] || '<p>Update from Preview Factory.</p>',
    text_body: textMap[step] || 'Update from Preview Factory.'
  }
}];
